settings.custom_liquid:
{%- assign lc_url = 'https://liff.line.me/2009213573-R2UyQXDf/inflow-routes/4339d1482916ade2b5e9' -%}

<section class="lc-hero">
  <div class="lc-hero__bg" style="background-image:url({{ 'lc-hero.jpg' | asset_url }})">
    <div class="lc-hero__overlay"></div>
    <div class="lc-hero__body">
      <h1 class="lc-hero__title">LINE会員登録で500円<br class="lc-sp-br">クーポンプレゼント</h1>
      <a href="{{ lc_url }}" class="lc-btn-green" target="_blank" rel="noopener">今すぐ友だち追加はこちら</a>
      <p class="lc-hero__note">登録後、クーポンのご案内をLINEでお送りします。</p>
    </div>
  </div>
</section>

<style>
.lc-sp-br { display:none; }
.lc-hero { margin:0; padding:0; }
.lc-hero__bg {
  position:relative;
  background-size:cover;
  background-position:center 40%;
  height:260px;
  display:flex; align-items:center; justify-content:center;
  overflow:hidden;
}
.lc-hero__overlay {
  position:absolute; inset:0;
  background:rgba(255,255,255,0.60);
}
.lc-hero__body {
  position:relative; z-index:1; text-align:center;
  padding:0 2rem; max-width:560px; margin:0 auto; width:100%;
}
.lc-hero__title {
  font-size:2.4rem; font-weight:800; color:#111;
  line-height:1.3; margin:0 0 24px; letter-spacing:.01em;
}
.lc-btn-green {
  display:inline-flex; align-items:center; justify-content:center;
  background:#06C755; color:#fff !important; text-decoration:none !important;
  font-size:1.5rem; font-weight:700; padding:14px 36px;
  border-radius:4px; transition:opacity .2s; letter-spacing:.03em; min-width:240px;
}
.lc-btn-green:hover { opacity:.85; }
.lc-hero__note {
  font-size:1.6rem; font-weight:700; color:#000; margin:12px 0 0;
}

@media (min-width:750px) {
  .lc-hero__bg { height:380px; }
  .lc-hero__title { font-size:3.0rem; margin-bottom:28px; }
  .lc-btn-green { font-size:1.6rem; padding:16px 48px; min-width:280px; }
  .lc-hero__note { font-size:1.8rem; }
}

@media (max-width:749px) {
  .lc-sp-br { display:block; }
  .lc-hero__body { padding-top:1.5rem; }
  .lc-hero__note { font-size:1.3rem; margin-left:-2rem; margin-right:-2rem; }
}
</style>

{%- assign lc_url = 'https://liff.line.me/2009213573-R2UyQXDf/inflow-routes/4339d1482916ade2b5e9' -%}

<section class="lc-addfriend">
  <div class="lc-addfriend__inner">
    <h2 class="lc-addfriend__title">友だち追加して登録する</h2>
    <p class="lc-addfriend__desc">登録は無料！<br>クーポンのご案内をLINEでお送りします。</p>
    <a href="{{ lc_url }}" class="lc-btn-green" target="_blank" rel="noopener">今すぐ友だち追加はこちら</a>
    <p class="lc-addfriend__note">ご注文時にクーポンが自動適用！<br>コード入力不要です。</p>
    <div class="lc-addfriend__qr">
      <img src="https://cdn.shopify.com/s/files/1/0790/0699/0569/files/EC_LINE500.png?v=1772093326" alt="LINE友だち追加 QRコード" class="lc-addfriend__qr-img" loading="lazy">
      <p class="lc-addfriend__qr-label">QRコードでも登録できます</p>
    </div>
  </div>
</section>

<style>
.lc-addfriend { padding:32px 0; background:#f4f4f4; }
.lc-addfriend__inner { max-width:560px; margin:0 auto; padding:0 2rem; text-align:center; }
.lc-addfriend__title {
  text-align:center; font-size:2.6rem; font-weight:700;
  letter-spacing:.06em; margin:0 0 14px; color:#111;
}
.lc-addfriend__desc { font-size:1.6rem; font-weight:700; color:#111; margin:0 0 24px; line-height:1.7; }
.lc-addfriend__note { font-size:1.6rem; font-weight:700; color:#111; margin:16px 0 0; line-height:1.8; }
.lc-addfriend__qr { margin-top:40px; }
.lc-addfriend__qr-img {
  display:block; width:180px; height:auto; margin:0 auto 12px;
}
.lc-addfriend__qr-label {
  font-size:1.3rem; font-weight:600; color:#555; margin:0;
}

@media (max-width:749px) {
  .lc-addfriend { padding:24px 0; }
  .lc-addfriend__title { font-size:2.2rem; margin-bottom:10px; }
  .lc-addfriend__desc { font-size:1.3rem; }
  .lc-addfriend__note { font-size:1.3rem; }
  .lc-addfriend__qr { margin-top:28px; }
  .lc-addfriend__qr-img { width:150px; }
}
</style>
